import React from "react";
const { useEffect, useRef } = React;

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;
  const heroRef = useRef(null);

  useEffect(() => {
    const els = heroRef.current?.querySelectorAll(".anim-in");
    if (!els) return;
    els.forEach((el, i) => {
      el.style.opacity = "0";
      el.style.transform = "translateY(24px)";
      el.style.transition = `opacity 0.65s ease ${i * 0.11}s, transform 0.65s ease ${i * 0.11}s`;
      requestAnimationFrame(() => {
        setTimeout(() => {
          el.style.opacity = "1";
          el.style.transform = "translateY(0)";
        }, 60);
      });
    });

    /* stat cards: staggered pop-in */
    const cells = heroRef.current?.querySelectorAll(".stat-cell");
    if (!cells) return;
    cells.forEach((cell, i) => {
      cell.style.opacity = "0";
      cell.style.transform = "translateY(20px) scale(0.94)";
      cell.style.transition = `opacity 0.55s ease ${0.5 + i * 0.1}s, transform 0.55s ease ${0.5 + i * 0.1}s`;
      setTimeout(() => {
        cell.style.opacity = "1";
        cell.style.transform = "translateY(0) scale(1)";
      }, 100);
    });
  }, []);

  const firstName = name.split(" ")[0];
  const lastName  = name.split(" ").slice(1).join(" ");

  return (
    <>
      <style>{`
        /* ── Keyframes ── */
        @keyframes pulse-ring {
          0%   { box-shadow: 0 0 0 0 rgba(0,229,255,0.55); }
          70%  { box-shadow: 0 0 0 8px rgba(0,229,255,0); }
          100% { box-shadow: 0 0 0 0 rgba(0,229,255,0); }
        }
        @keyframes blob-drift {
          0%,100% { transform: translate(0,0) scale(1); }
          33%     { transform: translate(22px,-16px) scale(1.06); }
          66%     { transform: translate(-12px,22px) scale(0.96); }
        }
        @keyframes shimmer {
          0%   { background-position: -200% center; }
          100% { background-position:  200% center; }
        }
        @keyframes card-glow-pulse {
          0%,100% { box-shadow: 0 0 0px rgba(0,229,255,0); }
          50%     { box-shadow: 0 0 20px rgba(0,229,255,0.15); }
        }
        @keyframes val-count {
          from { opacity: 0; transform: translateY(6px); }
          to   { opacity: 1; transform: translateY(0); }
        }

        /* ── Section ── */
        .hero-section {
          min-height: 100svh;
          display: flex;
          flex-direction: column;
          justify-content: center;
          padding: clamp(80px,10vh,110px) clamp(1.25rem,5vw,4rem) clamp(2.5rem,5vw,5rem);
          position: relative;
          overflow: hidden;
          box-sizing: border-box;
        }

        /* ── Inner content ── */
        .hero-inner {
          max-width: 900px;
          width: 100%;
          position: relative;
          z-index: 1;
        }

        /* ── Badge ── */
        .hero-badge {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: rgba(0,229,255,0.08);
          border: 1px solid rgba(0,229,255,0.22);
          border-radius: 99px;
          padding: 5px 15px;
          margin-bottom: 1.3rem;
        }
        .hero-badge-dot {
          width: 7px; height: 7px;
          border-radius: 50%;
          background: var(--accent);
          animation: pulse-ring 2s infinite;
          flex-shrink: 0;
        }
        .hero-badge-text {
          font-size: clamp(0.6rem, 1.1vw, 0.68rem);
          color: var(--accent);
          font-weight: 600;
          font-family: var(--font-display);
          letter-spacing: 0.07em;
          text-transform: uppercase;
          white-space: nowrap;
        }

        /* ── Name — ALWAYS one line, fluid size ── */
        .hero-name {
          font-family: var(--font-display);
          font-weight: 800;
          line-height: 1.0;
          letter-spacing: -0.03em;
          margin: 0 0 0.65rem;
          white-space: nowrap;
          overflow: visible;
          /* fluid: large on big screens, shrinks to fit any width */
          font-size: clamp(1.5rem, 9.5vw, 5.6rem);
        }
        .hero-name-gradient {
          background: linear-gradient(90deg, var(--accent) 0%, var(--accent2) 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        /* ── Subtitle ── */
        .hero-sub {
          font-family: var(--font-display);
          font-weight: 600;
          color: var(--muted);
          margin: 0 0 0.9rem;
          font-size: clamp(0.78rem, 1.55vw, 1.1rem);
          line-height: 1.5;
          word-break: break-word;
        }

        /* ── Tagline ── */
        .hero-tagline {
          font-size: clamp(0.8rem, 1.3vw, 0.97rem);
          color: var(--muted);
          max-width: 520px;
          line-height: 1.78;
          margin: 0 0 2rem;
        }

        /* ── Buttons ── */
        .hero-btns {
          display: flex;
          gap: 0.75rem;
          flex-wrap: wrap;
          align-items: center;
        }
        .btn-primary {
          background: var(--accent);
          color: #000;
          padding: 11px 26px;
          border-radius: 99px;
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.76rem, 1.05vw, 0.87rem);
          letter-spacing: 0.02em;
          transition: transform 0.22s, box-shadow 0.22s;
          display: inline-flex;
          align-items: center;
          gap: 6px;
          text-decoration: none;
          white-space: nowrap;
          cursor: pointer;
          flex-shrink: 0;
        }
        .btn-outline {
          background: transparent;
          color: var(--text);
          padding: 11px 26px;
          border-radius: 99px;
          border: 1px solid var(--border);
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.76rem, 1.05vw, 0.87rem);
          transition: border-color 0.22s, color 0.22s;
          text-decoration: none;
          white-space: nowrap;
          cursor: pointer;
          flex-shrink: 0;
        }

        /* ── Stats wrapper — matches hero-inner width ── */
        .stats-wrap {
          max-width: 900px;
          width: 100%;
          position: relative;
          z-index: 1;
          margin-top: clamp(2rem, 4.5vw, 3.5rem);
        }

        /* ── Stats grid ── */
        .stats-bar {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 10px;
          width: 100%;
        }

        /* ── Individual stat card ── */
        .stat-cell {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: 14px;
          padding: clamp(0.9rem, 2vw, 1.4rem) clamp(0.6rem, 1.5vw, 1.1rem);
          text-align: center;
          position: relative;
          overflow: hidden;
          cursor: default;
          animation: card-glow-pulse 3s ease-in-out infinite;
          transition:
            transform    0.28s cubic-bezier(0.34,1.56,0.64,1),
            box-shadow   0.28s ease,
            border-color 0.28s ease,
            background   0.22s ease;
          will-change: transform;
        }
        /* shimmer sweep pseudo-element */
        .stat-cell::after {
          content: "";
          position: absolute;
          inset: 0;
          background: linear-gradient(
            110deg,
            transparent 20%,
            rgba(0,229,255,0.07) 50%,
            transparent 80%
          );
          background-size: 200% 100%;
          opacity: 0;
          transition: opacity 0.3s;
          pointer-events: none;
        }
        .stat-cell:hover::after {
          opacity: 1;
          animation: shimmer 1s linear forwards;
        }
        .stat-cell:hover {
          transform: translateY(-6px) scale(1.04);
          box-shadow: 0 14px 36px rgba(0,229,255,0.2), 0 4px 14px rgba(0,0,0,0.35);
          border-color: rgba(0,229,255,0.48);
          background: var(--surface2);
        }
        /* stagger the glow-pulse so cards breathe at different times */
        .stat-cell:nth-child(1) { animation-delay: 0s; }
        .stat-cell:nth-child(2) { animation-delay: 0.75s; }
        .stat-cell:nth-child(3) { animation-delay: 1.5s; }
        .stat-cell:nth-child(4) { animation-delay: 2.25s; }

        .stat-val {
          font-family: var(--font-display);
          font-size: clamp(1.2rem, 2.8vw, 2.1rem);
          font-weight: 800;
          color: var(--accent);
          line-height: 1;
          white-space: nowrap;
          animation: val-count 0.4s ease both;
          display: block;
        }
        .stat-lbl {
          font-size: clamp(0.56rem, 0.85vw, 0.7rem);
          color: var(--muted);
          margin-top: 6px;
          font-weight: 500;
          line-height: 1.35;
          display: block;
        }

        /* ── BG blobs ── */
        .blob {
          position: absolute;
          border-radius: 50%;
          pointer-events: none;
          animation: blob-drift ease-in-out infinite;
          will-change: transform;
        }
        .blob-1 {
          top: -10%; right: -5%;
          width: clamp(160px,35vw,500px);
          height: clamp(160px,35vw,500px);
          background: radial-gradient(circle, rgba(124,58,237,0.13) 0%, transparent 70%);
          animation-duration: 14s;
        }
        .blob-2 {
          bottom: 0; left: -10%;
          width: clamp(120px,28vw,370px);
          height: clamp(120px,28vw,370px);
          background: radial-gradient(circle, rgba(0,229,255,0.09) 0%, transparent 70%);
          animation-duration: 10s;
          animation-delay: -4s;
        }

        /* ══════════════════════════════════════════
           RESPONSIVE BREAKPOINTS
        ══════════════════════════════════════════ */

        /* 4K / TV ≥ 1920px */
        @media (min-width: 1920px) {
          .hero-section { padding: 130px clamp(4rem,8vw,10rem) 6rem; }
          .hero-inner, .stats-wrap { max-width: 1200px; }
          .hero-name { font-size: clamp(5rem,6vw,7.5rem); }
          .hero-sub { font-size: 1.4rem; }
          .hero-tagline { font-size: 1.18rem; max-width: 680px; }
          .btn-primary, .btn-outline { font-size: 1rem; padding: 14px 34px; }
          .stat-val { font-size: 2.6rem; }
          .stat-lbl { font-size: 0.88rem; }
          .stats-bar { grid-template-columns: repeat(4,1fr); }
        }

        /* Tablet landscape 1025–1279 */
        @media (max-width: 1279px) and (min-width: 1025px) {
          .hero-name { font-size: clamp(2.5rem,6vw,4.2rem); }
          .hero-section { padding: 90px clamp(1.5rem,4vw,3rem) 3rem; }
          .stats-bar { grid-template-columns: repeat(4,1fr); }
        }

        /* Tablet portrait 768–1024 */
        @media (max-width: 1024px) {
          .hero-name { font-size: clamp(2.2rem,6.5vw,3.8rem); }
          .hero-section { padding: 90px clamp(1.25rem,4vw,2.5rem) 3rem; }
          .stats-bar { grid-template-columns: repeat(4,1fr); }
        }

        /* Large phone / small tablet 540–767 */
        @media (max-width: 767px) {
          .hero-name { font-size: clamp(1.9rem,8.5vw,3.2rem); }
          .hero-section { padding: 80px 1.5rem 2.5rem; }
          .stats-bar { grid-template-columns: repeat(2,1fr); }
          .stat-cell { padding: 1rem 0.75rem; border-radius: 12px; }
        }

        /* Standard phones 400–539 */
        @media (max-width: 539px) {
          .hero-section { padding: 76px 1.25rem 2.5rem; min-height: auto; }
          .hero-name { font-size: clamp(1.6rem,9.5vw,2.6rem); }
          .hero-btns { flex-direction: column; }
          .btn-primary, .btn-outline {
            width: 100%; justify-content: center;
            font-size: 0.875rem; padding: 13px 20px;
          }
          .stats-bar { grid-template-columns: repeat(2,1fr); gap: 8px; }
          .stat-val { font-size: 1.3rem; }
          .stat-lbl { font-size: 0.59rem; }
        }

        /* iPhone SE 320–399 */
        @media (max-width: 399px) {
          .hero-section { padding: 72px 1rem 2rem; }
          .hero-name { font-size: clamp(1.4rem,9.8vw,2rem); }
          .hero-sub { font-size: 0.75rem; }
          .hero-tagline { font-size: 0.78rem; }
          .hero-badge-text { font-size: 0.57rem; }
          .stats-bar { grid-template-columns: repeat(2,1fr); gap: 7px; }
          .stat-val { font-size: 1.15rem; }
        }

        /* Galaxy Fold < 320px */
        @media (max-width: 319px) {
          .hero-section { padding: 68px 0.85rem 1.75rem; }
          .hero-name { font-size: clamp(1.1rem,10vw,1.6rem); }
          .stats-bar { grid-template-columns: repeat(2,1fr); gap: 6px; }
          .stat-val { font-size: 1rem; }
          .stat-lbl { font-size: 0.55rem; }
        }

        /* Landscape phones */
        @media (max-height: 500px) and (max-width: 900px) {
          .hero-section { min-height: auto; padding-top: 68px; padding-bottom: 1.5rem; }
          .hero-name { font-size: clamp(1.4rem,5vw,2.2rem); }
          .hero-tagline { display: none; }
          .stats-wrap { margin-top: 1.25rem; }
          .stats-bar { grid-template-columns: repeat(4,1fr); gap: 6px; }
          .stat-cell { padding: 0.65rem 0.5rem; border-radius: 10px; }
          .stat-val { font-size: 1rem; }
          .stat-lbl { font-size: 0.52rem; }
        }

        /* iPad Pro 12.9 portrait */
        @media (min-width: 1024px) and (max-width: 1366px) and (orientation: portrait) {
          .hero-name { font-size: clamp(3rem,7vw,4.8rem); }
          .hero-section { padding-top: 115px; }
          .stats-bar { grid-template-columns: repeat(4,1fr); }
        }
      `}</style>

      <section className="hero-section" id="about" ref={heroRef}>
        {/* BG blobs */}
        <div className="blob blob-1" />
        <div className="blob blob-2" />

        <div className="hero-inner">
          {/* Badge */}
          <div className="hero-badge anim-in">
            <span className="hero-badge-dot" />
            <span className="hero-badge-text">Open to Opportunities</span>
          </div>

          {/* Name — single line always */}
          <h1 className="hero-name anim-in">
            {firstName}&nbsp;
            <span className="hero-name-gradient">{lastName}</span>
          </h1>

          {/* Subtitle */}
          <p className="hero-sub anim-in">
            {title} · <span style={{ color: "var(--accent3)" }}>{subtitle}</span>
          </p>

          {/* Tagline */}
          <p className="hero-tagline anim-in">{tagline}</p>

          {/* CTAs */}
          <div className="hero-btns anim-in">
            <a
              href="mailto:chavanak870@gmail.com"
              className="btn-primary"
              onMouseEnter={e => {
                e.currentTarget.style.transform = "translateY(-2px)";
                e.currentTarget.style.boxShadow = "0 8px 28px rgba(0,229,255,0.32)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = "none";
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              ✉ Get in Touch
            </a>
            <a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn-outline"
              onMouseEnter={e => {
                e.currentTarget.style.borderColor = "var(--accent2)";
                e.currentTarget.style.color = "var(--accent2)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.borderColor = "var(--border)";
                e.currentTarget.style.color = "var(--text)";
              }}
            >
              in LinkedIn
            </a>
          </div>
        </div>

        {/* Stats */}
        <div className="stats-wrap">
          <div className="stats-bar">
            {stats.map((s, i) => (
              <div key={i} className="stat-cell">
                <span
                  className="stat-val"
                  style={{ animationDelay: `${0.55 + i * 0.1}s` }}
                >
                  {s.value}
                </span>
                <span className="stat-lbl">{s.label}</span>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}
